import { removeRounding, formatCurrency, formatNumber, maskData, maskCustomerCode } from "../../src/lib/formatters";
import * as Utilities from "../../src/lib/utilities";

// Note, tests which modify the selectedLang cookie do work, but they do not provide the expected
// results because NodeJS does not have any other locales included in it by default.
describe("formatNumber", () => {
  it("Formats a number to the default locale", () => {
    expect(formatNumber(1000)).toBe("1,000");
  });
  it("Formats a string to the default locale", () => {
    expect(formatNumber("1000")).toBe("1,000");
  });
});

describe("formatCurrency", () => {
  it("Formats a INR currency", () => {
    Utilities.getCookie = jest.fn().mockReturnValue("en");
    expect(formatCurrency(654321.978, "INR")).toEqual("654,321.97");
  });
});

describe("removeRounding", () => {
  const formatableDataset = [
    {
      currency: "INR",
      locale: "en-GB",
      number: 100.198,
      expected: "100.19"
    },
    {
      currency: "INR",
      locale: "en-GB",
      number: 654321.978,
      expected: "654,321.97"
    },
    {
      currency: "INR",
      locale: "en-GB",
      number: 654321.990000000000001,
      expected: "654,321.99"
    },
    {
      currency: "INR",
      locale: "en-GB",
      number: 654321.1,
      expected: "654,321.10"
    },
    { currency: "INR", locale: "en-GB", number: 1235.0, expected: "1,235.00" },
    { currency: "INR", locale: "en-GB", number: 1235.0, expected: "1,235.00" },
    { currency: "INR", locale: "en-GB", number: 123.01, expected: "123.01" },
    { currency: "INR", locale: "en-GB", number: 123.15, expected: "123.15" },
    { currency: "INR", locale: "en-GB", number: 123.45, expected: "123.45" },
    { currency: "INR", locale: "en-GB", number: 123.96, expected: "123.96" },
    { currency: "INR", locale: "en-GB", number: 123.996, expected: "123.99" },
    { currency: "INR", locale: "en-GB", number: 123, expected: "123.00" },
    {
      currency: "INR",
      locale: "en-GB",
      number: 349000.0,
      expected: "349,000.00"
    },
    {
      currency: "INR",
      locale: "en-GB",
      number: 349000,
      expected: "349,000.00"
    },
    {
      currency: "INR",
      locale: "en-GB",
      number: 234356.998,
      expected: "234,356.99"
    },
    {
      currency: "INR",
      locale: "en-GB",
      number: 234356.995,
      expected: "234,356.99"
    },
    {
      currency: "USD",
      locale: "en-GB",
      number: 654321.978,
      expected: "654,321.97"
    },
    {
      currency: "USD",
      locale: "en-GB",
      number: 349000.0,
      expected: "349,000.00"
    },
    {
      currency: "USD",
      locale: "en-GB",
      number: 234356.998,
      expected: "234,356.99"
    },
    {
      currency: "USD",
      locale: "en-GB",
      number: 234356.95,
      expected: "234,356.95"
    },
    {
      currency: "USD",
      locale: "en-GB",
      number: 349000.1,
      expected: "349,000.10"
    },
    {
      currency: "DKK",
      locale: "en-GB",
      number: 654321.978,
      expected: "654,321.97"
    },
    {
      currency: "DKK",
      locale: "en-GB",
      number: 349000.0,
      expected: "349,000.00"
    },
    {
      currency: "DKK",
      locale: "en-GB",
      number: 234356.998,
      expected: "234,356.99"
    },
    {
      currency: "DKK",
      locale: "en-GB",
      number: 9999999.995,
      expected: "9,999,999.99"
    },
    {
      currency: "DKK",
      locale: "en-GB",
      number: 9999999.1,
      expected: "9,999,999.10"
    },
    {
      currency: "JPY",
      locale: "en-GB",
      number: 654321.978,
      expected: "654,321"
    },
    { currency: "JPY", locale: "en-GB", number: 349000.0, expected: "349,000" },
    {
      currency: "JPY",
      locale: "en-GB",
      number: 234356.998,
      expected: "234,356"
    },
    { currency: "JPY", locale: "en-GB", number: 123.456, expected: "123" },
    {
      currency: "JPY",
      locale: "en-GB",
      number: 234356.994,
      expected: "234,356"
    },
    {
      currency: "DJF",
      locale: "en-GB",
      number: 11659.5,
      expected: "11,659"
    },
    { currency: "JPY", locale: "en-GB", number: 234356.1, expected: "234,356" },
    { currency: "EUR", locale: "fr-FR", number: 100.0, expected: "100,00" },
    { currency: "EUR", locale: "fr-FR", number: 100000.0, expected: "100 000,00" },
    { currency: "EUR", locale: "fr-FR", number: 123.456, expected: "123,45" },
    { currency: "EUR", locale: "fr-FR", number: 999999999.988, expected: "999 999 999,98" },
    { currency: "INR", locale: "en-IN", number: 999999999.988, expected: "99,99,99,999.98" }
  ];

  formatableDataset.forEach((data) => {
    it(`should return with an ${data.expected} when the locale is ${data.locale} for ${data.currency} ${data.number}`, () => {
      const number = data.number;
      const func = new Intl.NumberFormat(data.locale, {
        style: "currency",
        currency: data.currency,
        currencyDisplay: "code"
      });
      const returnVal = removeRounding(number, func.format(number), func.formatToParts(number));
      expect(returnVal).toEqual(data.expected);
    });
  });

  describe("maskData", () => {
    const error1 = "Not a valid input type for masking. Only string and number types allowed and can not be empty";
    const error2 = "Not a valid config. Must include either fromStart or fromEnd";
    const error3 = "Not a valid config. Must include either fromStart or fromEnd, can not be both";
    const error4 = "Not a valid config. fromStart or fromEnd can not be negative";
    const error5 = "The number of chars need not to be masked can not be greater than input";
    test.each`
      input          | config                           | shouldErrorOut | expected
      ${""}          | ${null}                          | ${true}        | ${error1}
      ${null}        | ${null}                          | ${true}        | ${error1}
      ${undefined}   | ${{ fromStart: 2 }}              | ${true}        | ${error1}
      ${[]}          | ${{ fromStart: 2 }}              | ${true}        | ${error1}
      ${{}}          | ${{ fromStart: 2 }}              | ${true}        | ${error1}
      ${"123456789"} | ${{}}                            | ${true}        | ${error2}
      ${"123456789"} | ${null}                          | ${true}        | ${error2}
      ${"123456789"} | ${[]}                            | ${true}        | ${error2}
      ${"123456789"} | ${{ fromStart: 2 }}              | ${false}       | ${"12*******"}
      ${"123456789"} | ${{ fromEnd: 2 }}                | ${false}       | ${"*******89"}
      ${"123456789"} | ${{ fromStart: 9 }}              | ${false}       | ${"123456789"}
      ${"123456789"} | ${{ fromEnd: 9 }}                | ${false}       | ${"123456789"}
      ${"123456789"} | ${{ fromStart: 2, fromEnd: 9 }}  | ${true}        | ${error3}
      ${"123456789"} | ${{ fromStart: -2, fromEnd: 9 }} | ${true}        | ${error3}
      ${"123456789"} | ${{ fromStart: -2 }}             | ${true}        | ${error4}
      ${"123456789"} | ${{ fromEnd: -2 }}               | ${true}        | ${error4}
      ${"123456789"} | ${{ fromEnd: 12 }}               | ${true}        | ${error5}
      ${"123456789"} | ${{ fromStart: 12 }}             | ${true}        | ${error5}
    `("Calls the maskData and gives $expected", async ({ input, config, shouldErrorOut, expected }) => {
      try {
        const result = maskData(input, config);
        if (!shouldErrorOut) {
          expect(result).toBe(expected);
        }
      } catch (err) {
        expect(err.message).toBe(expected);
      }
    });
  });

  describe("maskCustomerCode", () => {
    it("Formats a customer code to the masked code skipping last three chars as unmasked", () => {
      expect(maskCustomerCode("123456789")).toBe("******789");
    });
  });
});
